logging.basicConfig(level=logging.INFO)
logger = logging.getLogger('llmXive.baseline_static_runner')

def load_test_set_ids() -> list:
    """Load test set IDs from the split generated by T014a."""
    config = load_config_from_file('config.json')
    path = Path(config['data']['processed']) / 'test_set.csv'
    if not path.exists():
        logger.error(f"Test set file not found: {path}")
        return []
    
    import pandas as pd
    df = pd.read_csv(path)
    if 'trajectory_id' not in df.columns:
        logger.error(f"Column 'trajectory_id' not found in {path}")
        return []
    
    return df['trajectory_id'].tolist()

